package org.elasticsearch.cluster.routing.allocation.decider;

import org.apache.logging.log4j.LogManager;
import org.apache.logging.log4j.Logger;
import org.elasticsearch.cluster.metadata.IndexMetadata;
import org.elasticsearch.cluster.node.DiscoveryNode;
import org.elasticsearch.cluster.routing.RoutingNode;
import org.elasticsearch.cluster.routing.ShardRouting;
import org.elasticsearch.cluster.routing.allocation.RoutingAllocation;
import org.elasticsearch.common.settings.ClusterSettings;
import org.elasticsearch.common.settings.Setting;
import org.elasticsearch.common.settings.Setting.Property;
import org.elasticsearch.common.settings.Settings;
import org.elasticsearch.injection.guice.Inject;

/**
 * The {@link PriorityAllocationDecider} enforces priority-based allocation constraints
 * during shard allocation and rebalancing.
 *
 * <p>
 * This decider ensures that shards are allocated to nodes with appropriate tier levels
 * based on their index's priority setting ({@code index.routing.allocation.priority}).
 * </p>
 *
 * <p>
 * Key features:
 * <ul>
 *   <li>Prevents critical shards from being allocated to low-tier nodes (if configured strictly)</li>
 *   <li>Allows fallback to lower tiers when higher tiers are unavailable</li>
 *   <li>Prevents unnecessary demotion of shards from higher to lower tiers</li>
 *   <li>Integrates seamlessly with other allocation deciders</li>
 *   <li>Can be enabled/disabled dynamically via cluster settings</li>
 * </ul>
 * </p>
 *
 * <p>
 * Decision logic:
 * <ol>
 *   <li>If priority allocation is disabled, return {@link Decision#ALWAYS}</li>
 *   <li>For allocation decisions: Allow if node tier matches or exceeds priority tier</li>
 *   <li>For remain decisions: Allow if preventing tier degradation</li>
 *   <li>Return {@link Decision#NO} only if strictly preventing misallocation</li>
 * </ol>
 * </p>
 *
 * @see AllocationDecider
 * @see PriorityShardsAllocator
 */
public class PriorityAllocationDecider extends AllocationDecider {

    private static final Logger logger = LogManager.getLogger(PriorityAllocationDecider.class);

    public static final String NAME = "priority";

    /**
     * Setting to enable or disable priority-based allocation constraints.
     * Default: false (backward compatible)
     */
    public static final Setting<Boolean> ENABLE_PRIORITY_ALLOCATION = Setting.boolSetting(
        "cluster.routing.allocation.priority.enabled",
        false,
        Property.Dynamic,
        Property.NodeScope
    );

    /**
     * Setting to enable strict mode for priority allocation.
     * In strict mode, critical shards cannot be allocated to low-tier nodes.
     * Default: false (allows fallback allocation)
     */
    public static final Setting<Boolean> PRIORITY_STRICT_MODE = Setting.boolSetting(
        "cluster.routing.allocation.priority.strict_mode",
        false,
        Property.Dynamic,
        Property.NodeScope
    );

    /**
     * Setting for the node attribute used to identify node tier.
     * Default: "tier" (values like "hot", "warm", "cold")
     */
    public static final Setting<String> PRIORITY_NODE_TIER_ATTRIBUTE = Setting.simpleString(
        "cluster.routing.allocation.priority.node_tier_attribute",
        "tier",
        Property.NodeScope
    );

    /**
     * Setting for the minimum priority threshold.
     * Shards with priority >= threshold trigger priority allocation rules.
     * Default: 0 (all indices are subject to priority rules)
     */
    public static final Setting<Integer> PRIORITY_THRESHOLD = Setting.intSetting(
        "cluster.routing.allocation.priority.threshold",
        0,
        Integer.MIN_VALUE,
        Property.Dynamic,
        Property.NodeScope
    );

    private volatile boolean priorityAllocationEnabled;
    private volatile boolean strictMode;
    private volatile String tierAttribute;
    private volatile int priorityThreshold;

    /**
     * Constructor for dependency injection.
     *
     * @param settings the cluster settings
     * @param clusterSettings the dynamic cluster settings
     */
    @Inject
    public PriorityAllocationDecider(Settings settings, ClusterSettings clusterSettings) {
        this.priorityAllocationEnabled = ENABLE_PRIORITY_ALLOCATION.get(settings);
        this.strictMode = PRIORITY_STRICT_MODE.get(settings);
        this.tierAttribute = PRIORITY_NODE_TIER_ATTRIBUTE.get(settings);
        this.priorityThreshold = PRIORITY_THRESHOLD.get(settings);

        // Watch for dynamic setting changes
        clusterSettings.initializeAndWatch(
            ENABLE_PRIORITY_ALLOCATION,
            value -> this.priorityAllocationEnabled = value
        );
        clusterSettings.initializeAndWatch(
            PRIORITY_STRICT_MODE,
            value -> this.strictMode = value
        );
        clusterSettings.initializeAndWatch(
            PRIORITY_NODE_TIER_ATTRIBUTE,
            value -> this.tierAttribute = value
        );
        clusterSettings.initializeAndWatch(
            PRIORITY_THRESHOLD,
            value -> this.priorityThreshold = value
        );
    }

    /**
     * Decides whether a shard can be allocated to a specific node.
     *
     * <p>
     * Decision logic:
     * <ul>
     *   <li>If priority allocation disabled: {@link Decision#ALWAYS}</li>
     *   <li>If shard priority below threshold: {@link Decision#ALWAYS}</li>
     *   <li>If node tier matches priority tier: {@link Decision#YES}</li>
     *   <li>If node tier exceeds priority requirement: {@link Decision#YES}</li>
     *   <li>If strict mode and node tier inadequate: {@link Decision#NO}</li>
     *   <li>Otherwise (fallback allowed): {@link Decision#THROTTLE}</li>
     * </ul>
     * </p>
     *
     * @param shardRouting the shard to allocate
     * @param node the target node
     * @param allocation the current allocation state
     * @return allocation decision
     */
    @Override
    public Decision canAllocate(ShardRouting shardRouting, RoutingNode node, RoutingAllocation allocation) {
        if (!priorityAllocationEnabled) {
            return Decision.ALWAYS;
        }

        // Get shard's index metadata
        IndexMetadata indexMetadata = allocation.metadata().getIndexSafe(shardRouting.index());
        int indexPriority = getIndexPriority(indexMetadata);

        // Skip if below priority threshold
        if (indexPriority < priorityThreshold) {
            return Decision.ALWAYS;
        }

        // Get node tier
        DiscoveryNode discoveryNode = node.node();
        String nodeTier = getNodeTier(discoveryNode);

        // TODO: Implement tier-based decision logic
        // Compare node tier with priority tier requirement
        // Return YES if suitable
        // Return NO if strict mode and unsuitable
        // Return THROTTLE if fallback-allowed and suboptimal

        return Decision.ALWAYS;
    }

    /**
     * Decides whether a shard can remain on a specific node.
     *
     * <p>
     * This is used to prevent unnecessary shard movement. Key logic:
     * <ul>
     *   <li>If shard on higher tier than required: {@link Decision#YES} (don't downgrade)</li>
     *   <li>If shard on matching tier: {@link Decision#YES}</li>
     *   <li>If shard on lower tier than ideal but no higher-tier space: {@link Decision#YES}</li>
     *   <li>Otherwise, may trigger rebalancing to better tier</li>
     * </ul>
     * </p>
     *
     * @param indexMetadata the index metadata
     * @param shardRouting the shard
     * @param node the current node
     * @param allocation the current allocation state
     * @return decision on whether shard can remain
     */
    @Override
    public Decision canRemain(IndexMetadata indexMetadata, ShardRouting shardRouting, RoutingNode node,
                             RoutingAllocation allocation) {
        if (!priorityAllocationEnabled) {
            return Decision.ALWAYS;
        }

        int indexPriority = getIndexPriority(indexMetadata);

        // Skip if below priority threshold
        if (indexPriority < priorityThreshold) {
            return Decision.ALWAYS;
        }

        // Get current node tier
        DiscoveryNode discoveryNode = node.node();
        String currentNodeTier = getNodeTier(discoveryNode);

        // TODO: Implement "can remain" decision logic
        // Prevent shard from being moved to lower tier unnecessarily
        // Allow remaining if:
        // 1. Node tier is suitable for priority
        // 2. Moving would only happen to lower tier (not allowed)
        // 3. This node is already allocated the shard (stable state)

        return Decision.ALWAYS;
    }

    /**
     * Decides whether a shard can be rebalanced.
     *
     * <p>
     * This method allows priority-aware rebalancing decisions:
     * <ul>
     *   <li>Allow rebalancing of low-priority shards when needed for balance</li>
     *   <li>Minimize rebalancing of high-priority critical shards</li>
     *   <li>Prioritize moving critical shards to better tiers</li>
     * </ul>
     * </p>
     *
     * @param shardRouting the shard to potentially rebalance
     * @param allocation the current allocation state
     * @return decision on whether shard can be rebalanced
     */
    @Override
    public Decision canRebalance(ShardRouting shardRouting, RoutingAllocation allocation) {
        if (!priorityAllocationEnabled) {
            return Decision.ALWAYS;
        }

        // TODO: Implement priority-aware rebalancing logic
        // Allow rebalancing based on:
        // 1. Shard's index priority
        // 2. Current node vs target node tier match
        // 3. Overall cluster balance needs

        return Decision.ALWAYS;
    }

    /**
     * Extracts priority value from index settings.
     *
     * @param indexMetadata the index metadata
     * @return priority value (0 = default/neutral)
     */
    private int getIndexPriority(IndexMetadata indexMetadata) {
        try {
            return indexMetadata.getSettings().getAsInt(
                PriorityShardsAllocator.INDEX_ROUTING_ALLOCATION_PRIORITY.getKey(),
                0  // Default value
            );
        } catch (Exception e) {
            logger.warn(
                "Failed to parse priority setting for index [{}], using default",
                indexMetadata.getIndex().getName(),
                e
            );
            return 0;
        }
    }

    /**
     * Gets the tier attribute value from a node's attributes.
     *
     * @param node the discovery node
     * @return tier value (e.g., "hot", "warm", "cold") or "unknown"
     */
    private String getNodeTier(DiscoveryNode node) {
        if (node == null || node.getAttributes() == null) {
            return "unknown";
        }
        String tier = node.getAttributes().get(tierAttribute);
        return tier != null ? tier : "unknown";
    }

    /**
     * Determines the required tier level for a given priority value.
     *
     * @param priority the index priority
     * @return required tier ("hot", "warm", "cold")
     */
    private String getRequiredTierForPriority(int priority) {
        // Priority-to-tier mapping (configurable via decider parameters)
        // Example mapping:
        // priority >= 100: "hot" (highest tier)
        // priority >= 0:   "warm" (medium tier)
        // priority < 0:    "cold" (lowest tier)

        if (priority >= 100) {
            return "hot";
        } else if (priority >= 0) {
            return "warm";
        } else {
            return "cold";
        }
    }

    /**
     * Compares two tier values by their hierarchy level.
     *
     * @param tier1 first tier
     * @param tier2 second tier
     * @return negative if tier1 < tier2, zero if equal, positive if tier1 > tier2
     *         (in terms of tier hierarchy: hot > warm > cold > unknown)
     */
    private int compareTiers(String tier1, String tier2) {
        // Tier hierarchy: hot (3) > warm (2) > cold (1) > unknown (0)
        return getTierLevel(tier1) - getTierLevel(tier2);
    }

    /**
     * Returns the numeric level of a tier (for comparison).
     *
     * @param tier the tier name
     * @return tier level (higher = better)
     */
    private int getTierLevel(String tier) {
        switch (tier) {
            case "hot":
                return 3;
            case "warm":
                return 2;
            case "cold":
                return 1;
            default:
                return 0;  // unknown
        }
