import org.elasticsearch.common.settings.Settings;
import org.elasticsearch.injection.guice.Inject;

/**
 * The {@link PriorityAllocationDecider} enforces priority-based allocation constraints
 * during shard allocation and rebalancing.
 *
 * <p>
 * This decider ensures that shards are allocated to nodes with appropriate tier levels
 * based on their index's priority setting ({@code index.routing.allocation.priority}).
 * </p>
 *
 * <p>
 * Key features:
 * <ul>
 *   <li>Prevents critical shards from being allocated to low-tier nodes (if configured strictly)</li>
 *   <li>Allows fallback to lower tiers when higher tiers are unavailable</li>
 *   <li>Prevents unnecessary demotion of shards from higher to lower tiers</li>
 *   <li>Integrates seamlessly with other allocation deciders</li>
 *   <li>Can be enabled/disabled dynamically via cluster settings</li>
 * </ul>
 * </p>
 *
 * <p>
 * Decision logic:
 * <ol>
 *   <li>If priority allocation is disabled, return {@link Decision#ALWAYS}</li>
 *   <li>For allocation decisions: Allow if node tier matches or exceeds priority tier</li>
 *   <li>For remain decisions: Allow if preventing tier degradation</li>
 *   <li>Return {@link Decision#NO} only if strictly preventing misallocation</li>
 * </ol>
 * </p>
 *
 * @see AllocationDecider
 * @see PriorityShardsAllocator
 */
public class PriorityAllocationDecider extends AllocationDecider {

    private static final Logger logger = LogManager.getLogger(PriorityAllocationDecider.class);

    public static final String NAME = "priority";

    /**
     * Setting to enable or disable priority-based allocation constraints.
     * Default: false (backward compatible)
     */
    public static final Setting<Boolean> ENABLE_PRIORITY_ALLOCATION = Setting.boolSetting(
        "cluster.routing.allocation.priority.enabled",
        false,
        Property.Dynamic,
        Property.NodeScope
    );

    /**
     * Setting to enable strict mode for priority allocation.
     * In strict mode, critical shards cannot be allocated to low-tier nodes.
     * Default: false (allows fallback allocation)
     */
    public static final Setting<Boolean> PRIORITY_STRICT_MODE = Setting.boolSetting(
        "cluster.routing.allocation.priority.strict_mode",
        false,
        Property.Dynamic,
        Property.NodeScope
    );

    /**
     * Setting for the node attribute used to identify node tier.
     * Default: "tier" (values like "hot", "warm", "cold")
     */
    public static final Setting<String> PRIORITY_NODE_TIER_ATTRIBUTE = Setting.simpleString(
        "cluster.routing.allocation.priority.node_tier_attribute",
        "tier",
        Property.NodeScope
    );

    /**
     * Setting for the minimum priority threshold.
     * Shards with priority >= threshold trigger priority allocation rules.
     * Default: 0 (all indices are subject to priority rules)
     */
    public static final Setting<Integer> PRIORITY_THRESHOLD = Setting.intSetting(
        "cluster.routing.allocation.priority.threshold",
        0,
        Integer.MIN_VALUE,
        Property.Dynamic,
        Property.NodeScope
    );

    private volatile boolean priorityAllocationEnabled;
    private volatile boolean strictMode;
    private volatile String tierAttribute;
    private volatile int priorityThreshold;

    /**
     * Constructor for dependency injection.
     *
     * @param settings the cluster settings
     * @param clusterSettings the dynamic cluster settings
     */
    @Inject
    public PriorityAllocationDecider(Settings settings, ClusterSettings clusterSettings) {
        this.priorityAllocationEnabled = ENABLE_PRIORITY_ALLOCATION.get(settings);
        this.strictMode = PRIORITY_STRICT_MODE.get(settings);
        this.tierAttribute = PRIORITY_NODE_TIER_ATTRIBUTE.get(settings);
        this.priorityThreshold = PRIORITY_THRESHOLD.get(settings);

        // Watch for dynamic setting changes
        clusterSettings.initializeAndWatch(
            ENABLE_PRIORITY_ALLOCATION,
            value -> this.priorityAllocationEnabled = value
        );
        clusterSettings.initializeAndWatch(
            PRIORITY_STRICT_MODE,
            value -> this.strictMode = value
        );
        clusterSettings.initializeAndWatch(
            PRIORITY_NODE_TIER_ATTRIBUTE,
            value -> this.tierAttribute = value
        );
        clusterSettings.initializeAndWatch(
            PRIORITY_THRESHOLD,
            value -> this.priorityThreshold = value
        );
