        if (!priorityAllocationEnabled) {
            return Decision.ALWAYS;
        }

        int indexPriority = getIndexPriority(indexMetadata);

        // Skip if below priority threshold
        if (indexPriority < priorityThreshold) {
            return Decision.ALWAYS;
        }

        // Get current node tier
        DiscoveryNode discoveryNode = node.node();
        String currentNodeTier = getNodeTier(discoveryNode);

        // TODO: Implement "can remain" decision logic
