        // priority >= 100: "hot" (highest tier)
        // priority >= 0:   "warm" (medium tier)
        // priority < 0:    "cold" (lowest tier)

        if (priority >= 100) {
            return "hot";
        } else if (priority >= 0) {
            return "warm";
        } else {
            return "cold";
        }
    }

    /**
     * Compares two tier values by their hierarchy level.
     *
     * @param tier1 first tier
     * @param tier2 second tier
     * @return negative if tier1 < tier2, zero if equal, positive if tier1 > tier2
     *         (in terms of tier hierarchy: hot > warm > cold > unknown)
     */
    private int compareTiers(String tier1, String tier2) {
        // Tier hierarchy: hot (3) > warm (2) > cold (1) > unknown (0)
        return getTierLevel(tier1) - getTierLevel(tier2);
    }

    /**
     * Returns the numeric level of a tier (for comparison).
     *
     * @param tier the tier name
     * @return tier level (higher = better)
     */
    private int getTierLevel(String tier) {
        switch (tier) {
            case "hot":
                return 3;
            case "warm":
                return 2;
            case "cold":
                return 1;
            default:
                return 0;  // unknown
        }
    }

    /**
     * Checks if a node's tier is adequate for the given priority.
     *
     * @param nodeTier the node's tier
     * @param requiredTier the minimum required tier
     * @return true if node tier >= required tier
     */
    private boolean isTierAdequate(String nodeTier, String requiredTier) {
        return compareTiers(nodeTier, requiredTier) >= 0;
    }

    // Getters for testing and configuration

    public boolean isPriorityAllocationEnabled() {
        return priorityAllocationEnabled;
    }

    public boolean isStrictMode() {
        return strictMode;
    }

    public String getTierAttribute() {
        return tierAttribute;
    }

    public int getPriorityThreshold() {
        return priorityThreshold;
    }
}
